(b) => {
  const apiKey = b.getValue('apiKey');
  const instanceId = b.getValue('instanceId');
  const phone = b.getValue('phone');
  const message = b.getValue('message');
  const target = b.getValue('target') || 'messageResult';
  return `const ${target} = await (async () => {
  const response = await fetch('https://api.uazapi.com/instance/${instanceId}/sendText', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'apikey': '${apiKey}'
    },
    body: JSON.stringify({
      phone: '${phone}',
      message: ${message}
    })
  });
  const data = await response.json();
  if(window.__addLog) window.__addLog('WhatsApp message sent to ' + '${phone}', 'info');
  return data;
})();`;
}

(b) => {
  const apiKey = b.getValue('apiKey');
  const instanceId = b.getValue('instanceId');
  const phone = b.getValue('phone');
  const mediaType = b.getValue('mediaType');
  const mediaUrl = b.getValue('mediaUrl');
  const caption = b.getValue('caption');
  const target = b.getValue('target') || 'mediaResult';
  const endpoint = mediaType === 'image' ? 'sendImage' : mediaType === 'video' ? 'sendVideo' : mediaType === 'audio' ? 'sendAudio' : 'sendDocument';
  return `const ${target} = await (async () => {
  const response = await fetch('https://api.uazapi.com/instance/${instanceId}/${endpoint}', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'apikey': '${apiKey}'
    },
    body: JSON.stringify({
      phone: '${phone}',
      url: ${mediaUrl},
      caption: ${caption || 'null'}
    })
  });
  const data = await response.json();
  if(window.__addLog) window.__addLog('WhatsApp media sent to ' + '${phone}', 'info');
  return data;
})();`;
}

